typedef struct {
    uint32_t current_state;      // 0=init, 1=read, 2=validate, 3=check, 4=accept, 5=reject
    uint32_t head_index;         // tape head position
    uint32_t tape_length;        // tape length
    uint32_t steps_taken;        // steps taken so far
    uint32_t max_steps;          // maximum steps allowed before halt
    uint32_t noise_level;        // noise level in percentage (0-100)
    uint32_t state_complexity;   // count of states (Q)
    uint32_t halt_status;        // 0=running, 1=accepted, 2=rejected
} turing_status_t;

